/* eslint-disable max-depth */
import without from 'lodash/without';
import pick from 'lodash/pick';
import type { ReactElement } from 'react';
import React, { cloneElement, isValidElement, memo } from 'react';
import { shallowEqualObjects } from 'shallow-equal';
import { isFunction, isReactHTMLElement, isReactInputElement, omit } from '../util';
import type {
  FieldProps,
  UseFieldInternalReturnValue,
  UseFieldProps,
  UseFieldReturnValue,
} from './internal/useFieldInternal';
import { useFieldInternal } from './internal/useFieldInternal';
import type { Path } from './shared';
import { marshalNamePath } from './shared';
import { useEventCallback } from '../hooks/useEventCallback';

interface FieldChildProps<FieldValue> {
  value?: FieldValue;
  checked?: boolean;
  error?: boolean;
}

export function useField(props: UseFieldProps): UseFieldReturnValue {
  const returnValue = useFieldInternal(props);
  return pick(returnValue, ['value', 'error', 'handleChange']);
}

export const FieldPropsAreEqual = (prevProps: { name?: Path }, nextProps: { name?: Path }) => {
  if (!shallowEqualObjects(omit(prevProps, ['name']), omit(nextProps, ['name']))) {
    return false;
  }
  if (
    (prevProps.name === undefined && nextProps.name === undefined) ||
    (prevProps.name !== undefined &&
      nextProps.name !== undefined &&
      marshalNamePath(prevProps.name) === marshalNamePath(nextProps.name))
  ) {
    return true;
  }
  return false;
};

export const Field = memo(function (props: FieldProps): ReactElement {
  const { children, valuePropName, validateStatus } = props;
  const fieldCtx = useFieldInternal({ ...props });
  const { value, handleChange, error, allValidateTriggers, trigger, validateField } = fieldCtx;
  const isError = validateStatus === 'error' || Boolean(error);
  /**
   * clone 给子元素的 handleChange 函数
   */
  const composedHandleChange = useEventCallback<UseFieldInternalReturnValue['handleChange']>((...args) => {
    handleChange(...args);
    if ('props' in children && trigger in children.props && isFunction(children.props[trigger])) {
      children.props[trigger](...args);
    }
  });

  /**
   * 所有 trigger validateTrigger 相关的回调函数
   */
  const mergedChildProps = (() => {
    const mergedTrigger = 'props' in children ? { ...children.props } : {};

    if ('props' in children) {
      mergedTrigger[trigger] = composedHandleChange;
    }

    without(allValidateTriggers, trigger).forEach((triggerName: string) => {
      const originTrigger = mergedTrigger[triggerName];
      mergedTrigger[triggerName] = (...args: any[]) => {
        if (isFunction(originTrigger)) {
          originTrigger(...args);
        }
        validateField({ triggerName });
      };
    });

    return mergedTrigger;
  })();

  if (isFunction(children)) {
    return <>{children(pick(fieldCtx, ['value', 'error', 'handleChange']))}</>;
  } else if (isValidElement(children)) {
    if (isReactHTMLElement(children)) {
      // html tags
      if (isReactInputElement(children)) {
        switch (children.props.type) {
          case 'radio':
          case 'checkbox':
            return cloneElement(children, {
              [valuePropName ?? 'checked']: value,
              ...mergedChildProps,
            });
          case 'file':
            throw new Error(
              'Field cannot be used on file inputs since they are read-only. Use a onChange listener instead.',
            );
          default:
            return cloneElement(children, {
              [valuePropName ?? 'value']: value,
              ...mergedChildProps,
            });
        }
      } else {
        return cloneElement(children, {
          [valuePropName ?? 'value']: value,
          ...mergedChildProps,
        });
      }
    }
    return cloneElement(children as ReactElement<FieldChildProps<any>>, {
      [valuePropName ?? 'value']: value,
      error: isError,
      ...mergedChildProps,
    });
  } else {
    return children;
  }
}, FieldPropsAreEqual);
if (__DEV__) {
  Field.displayName = 'Field';
}
